void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("PedroSangre_1");			link.l1 = StringFromKey("PedroSangre_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("PedroSangre_3");			link.l1 = StringFromKey("PedroSangre_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("PedroSangre_5");			link.l1 = StringFromKey("PedroSangre_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("PedroSangre_7");			link.l1 = StringFromKey("PedroSangre_8");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("PedroSangre_9");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "5";			AddDialogExitQuest("FL8_s16");		break;		case "5":			dialog.text = StringFromKey("PedroSangre_10");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "5";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}